import { DateView } from "@mui/x-date-pickers";
import { Dayjs } from "dayjs";
import { useState } from "react";

import { useTimePeriodControls } from "../TimePeriodContext.tsx";
import { StaticCalendar } from "./StaticCalendar.tsx";

type MonthPickerProps = {
  onMonthChange: (date: Dayjs) => void;
};

export function MonthPicker({ onMonthChange }: MonthPickerProps) {
  const { selectedDay, maxDateRangeFrom, maxDateRangeTo } =
    useTimePeriodControls();

  const [value, setValue] = useState<Dayjs | null>(selectedDay);
  const [view, setView] = useState<DateView>("month");

  return (
    <StaticCalendar
      value={value}
      view={view}
      sx={{
        "& .MuiDateCalendar-root": {
          height: "100%",
          minHeight: "260px",
        },
      }}
      onViewChange={setView}
      onChange={(val) => {
        setValue(val);
        if (view === "month" && val) {
          onMonthChange(val);
        }
      }}
      minDate={maxDateRangeFrom}
      maxDate={maxDateRangeTo}
      views={["year", "month"]}
      openTo="month"
    />
  );
}

import { PickersDay } from "@mui/x-date-pickers";
import type { PickersDayProps } from "@mui/x-date-pickers/PickersDay";
import { Dayjs } from "dayjs";
import type { ComponentType } from "react";
import { useState } from "react";

import { useTimePeriodControls } from "../TimePeriodContext.tsx";
import { StaticCalendar } from "./StaticCalendar.tsx";

type WeekPickerProps = {
  onWeekChange: (date: Dayjs) => void;
};

export function WeekPicker({ onWeekChange }: WeekPickerProps) {
  const { selectedDay, maxDateRangeFrom, maxDateRangeTo } =
    useTimePeriodControls();

  const [value, setValue] = useState<Dayjs | null>(selectedDay);
  const [view, setView] = useState<"year" | "month" | "day">("day");

  return (
    <StaticCalendar
      value={value}
      view={view}
      onViewChange={setView}
      sx={{
        "& .MuiDateCalendar-root": {
          height: "100%",
          minHeight: "354px",
        },
        "& .MuiPickersSlideTransition-root": {
          minHeight: "260px",
        },
      }}
      onChange={(val) => {
        setValue(val);
        if (view === "day" && val) {
          onWeekChange(val);
        }
      }}
      minDate={maxDateRangeFrom}
      maxDate={maxDateRangeTo}
      views={["year", "month", "day"]}
      showDaysOutsideCurrentMonth
      slots={{
        day: WeekPickerDay as ComponentType<PickersDayProps<Dayjs>>,
      }}
      slotProps={{
        day: {
          selectedDay: value,
          minDate: maxDateRangeFrom,
          maxDate: maxDateRangeTo,
        } as Record<string, unknown>,
      }}
    />
  );
}

type WeekPickerDayProps = PickersDayProps<Dayjs> & {
  selectedDay: Dayjs | null;
  minDate: Dayjs;
  maxDate: Dayjs;
};

/**
 * Custom day component that highlights the entire week row when in week view
 */
export function WeekPickerDay({
  day,
  selectedDay,
  minDate,
  maxDate,
  ...other
}: WeekPickerDayProps) {
  if (!selectedDay) {
    return <PickersDay {...other} day={day} />;
  }

  const startOfWeek = selectedDay.startOf("isoWeek");
  const endOfWeek = selectedDay.endOf("isoWeek");
  const isInSelectedWeek =
    day.isSame(startOfWeek, "day") ||
    (day.isAfter(startOfWeek) && day.isBefore(endOfWeek)) ||
    day.isSame(endOfWeek, "day");

  const isStartOfWeek = day.isSame(startOfWeek, "day");
  const isEndOfWeek = day.isSame(endOfWeek, "day");

  // Disable days outside the available range
  const isOutsideRange =
    day.isBefore(minDate, "day") || day.isAfter(maxDate, "day");

  return (
    <PickersDay
      {...other}
      day={day}
      disabled={isOutsideRange}
      disableMargin
      selected={isInSelectedWeek}
      sx={{
        padding: 2.5,
        ...(isInSelectedWeek && {
          backgroundColor: "primary.main",
          color: "primary.contrastText",
          borderRadius: 0,
          "&:hover": {
            backgroundColor: "primary.dark",
          },
          "&:focus": {
            backgroundColor: "primary.main",
          },
        }),
        ...(isStartOfWeek &&
          isInSelectedWeek && {
            borderTopLeftRadius: "50%",
            borderBottomLeftRadius: "50%",
          }),
        ...(isEndOfWeek &&
          isInSelectedWeek && {
            borderTopRightRadius: "50%",
            borderBottomRightRadius: "50%",
          }),
      }}
    />
  );
}

